const customers = $input.all().map(i => i.json);
const allCustomers = Array.isArray(customers[0]) ? customers[0] : customers;

const now = new Date();
const thirtyDaysAgo = new Date(now - 30 * 24 * 60 * 60 * 1000);
const ninetyDaysAgo = new Date(now - 90 * 24 * 60 * 60 * 1000);
const fourteenDaysAgo = new Date(now - 14 * 24 * 60 * 60 * 1000);

const eligible = [];

for (const c of allCustomers) {
  if (!c.email || !c.name) continue;

  // Must be paying for 30+ days
  const createdAt = new Date(c.created_at);
  if (createdAt > thirtyDaysAgo) continue;

  // Must not be in churn risk
  if (c.churn_risk_status === 'high' || c.churn_risk_status === 'churned') continue;

  // Must not have been asked in last 90 days
  if (c.review_requested_at) {
    const lastAsked = new Date(c.review_requested_at);
    if (lastAsked > ninetyDaysAgo) continue;
  }

  // Should have logged in within last 14 days (active user)
  if (c.last_login_at) {
    const lastLogin = new Date(c.last_login_at);
    if (lastLogin < fourteenDaysAgo) continue;
  }

  const daysSinceSignup = Math.floor((now - createdAt) / (1000 * 60 * 60 * 24));

  eligible.push({
    json: {
      id: c.id,
      email: c.email,
      name: c.name,
      daysSinceSignup
    }
  });

  // Cap at 10 per week to avoid looking spammy
  if (eligible.length >= 10) break;
}

if (eligible.length === 0) {
  return [{ json: { _noEligible: true, count: 0 } }];
}

return eligible;

const { name, email, daysSinceSignup } = $input.first().json;

const timePhrase = daysSinceSignup > 60
  ? 'a couple months'
  : 'about a month';

const html = `
