return [{
  json: {
    ...$input.first().json,
    emailSubject: `Quick favor, ${name}?`,
    emailHtml: html
  }
}];

const customer = $('Build Review Request Email').first().json;
const resendResponse = $input.first().json;
const sent = !!(resendResponse.id);

return [{
  json: {
    customerId: customer.id,
    email: customer.email,
    name: customer.name,
    sent,
    resendId: resendResponse.id || null,
    error: resendResponse.error || null
  }
}];

// Collect all results from the batch
const items = $input.all();
let sentCount = 0;
let failedCount = 0;
const names = [];

for (const item of items) {
  const data = item.json;
  // Check if this was a successful send from earlier node
  if (data.sent || data.resendId) {
    sentCount++;
    if (data.name) names.push(data.name);
  } else if (data.error) {
    failedCount++;
  }
}

// If we came from the no-eligible path
if (sentCount === 0 && failedCount === 0) {
  sentCount = 0;
}

const nameList = names.length > 0 ? names.join(', ') : 'none';

const message = `📋 *Review Collector Weekly Summary*\n\n` +
  `Review requests sent: *${sentCount}*\n` +
  (failedCount > 0 ? `Failed to send: *${failedCount}*\n` : '') +
  (names.length > 0 ? `Customers contacted: ${nameList}\n` : '') +
  `\nWeek of ${new Date().toISOString().split('T')[0]}`;

return [{
  json: {
    text: message,
    sentCount,
    failedCount
  }
}];

// No eligible customers this week
return [{
  json: {
    sent: false,
    sentCount: 0,
    text: '📋 *Review Collector Weekly Summary*\n\nNo eligible customers to request reviews from this week.\n\nWeek of ' + new Date().toISOString().split('T')[0]
  }
}];

const payload = $input.first().json.body || $input.first().json;

const customerId = payload.customerId || payload.customer_id || '';
const email = payload.email || '';
const name = payload.name || 'there';
const platform = payload.platform || 'unknown';
const rating = payload.rating || 0;
const reviewText = payload.review_text || '';

if (!email && !customerId) {
  throw new Error('Missing required field: email or customerId');
}

return [{
  json: {
    customerId,
    email,
    name,
    platform,
    rating,
    reviewText,
    isPositive: rating >= 4
  }
}];

const { name, email, platform, rating } = $input.first().json;

